@Service
class SamlObjectBuilder {

    public <T extends SAMLObject> T build(Class<T> clazz, QName qName) {
        XMLObjectBuilderFactory builderFactory = XMLObjectProviderRegistrySupport.getBuilderFactory();
        return clazz.cast(builderFactory.getBuilder(qName).buildObject(qName));
    }

    public Issuer issuer(String value) {
        Issuer issuer = build(Issuer.class, Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(value);
        return issuer;
    }

    public NameIDPolicy nameIdPolicy() {
        NameIDPolicy policy = build(NameIDPolicy.class, NameIDPolicy.DEFAULT_ELEMENT_NAME);
        policy.setAllowCreate(true);
        policy.setFormat(NameIDType.PERSISTENT);
        return policy;
    }
}

