@Service
class SamlMetadataService {

    private final SamlProperties properties;
    private final SamlObjectBuilder builder;
    private final SamlCredentialService credentialService;

    SamlMetadataService(SamlProperties properties, SamlObjectBuilder builder, SamlCredentialService credentialService) {
        this.properties = properties;
        this.builder = builder;
        this.credentialService = credentialService;
    }

    public String generateMetadata() {
        EntityDescriptor entityDescriptor = builder.build(EntityDescriptor.class, EntityDescriptor.DEFAULT_ELEMENT_NAME);
        entityDescriptor.setEntityID(properties.getSpEntityId());

        SPSSODescriptor spDescriptor = builder.build(SPSSODescriptor.class, SPSSODescriptor.DEFAULT_ELEMENT_NAME);
        spDescriptor.setAuthnRequestsSigned(properties.isSignAuthnRequest());
        spDescriptor.setWantAssertionsSigned(properties.isWantAssertionsSigned());
        spDescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        AssertionConsumerService acs = builder.build(AssertionConsumerService.class, AssertionConsumerService.DEFAULT_ELEMENT_NAME);
        acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acs.setLocation(properties.getAcsUrl());
        acs.setIndex(0);
        acs.setIsDefault(true);
        spDescriptor.getAssertionConsumerServices().add(acs);

        SingleLogoutService slo = builder.build(SingleLogoutService.class, SingleLogoutService.DEFAULT_ELEMENT_NAME);
        slo.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        slo.setLocation(properties.getSloUrl());
        spDescriptor.getSingleLogoutServices().add(slo);

        NameIDFormat nif = builder.build(NameIDFormat.class, NameIDFormat.DEFAULT_ELEMENT_NAME);
        nif.setURI(NameIDType.PERSISTENT);
        spDescriptor.getNameIDFormats().add(nif);

        BasicX509Credential credential = credentialService.getSpCredential();
        if (credential.getEntityCertificate() != null) {
            KeyDescriptor keyDescriptor = builder.build(KeyDescriptor.class, KeyDescriptor.DEFAULT_ELEMENT_NAME);
            keyDescriptor.setUse(UsageType.SIGNING);

            org.opensaml.xmlsec.signature.KeyInfo keyInfo = buildKeyInfo(credential.getEntityCertificate());
            keyDescriptor.setKeyInfo(keyInfo);
            spDescriptor.getKeyDescriptors().add(keyDescriptor);
        }

        entityDescriptor.getRoleDescriptors().add(spDescriptor);

        try {
            org.w3c.dom.Element element = org.opensaml.core.xml.util.XMLObjectSupport.marshall(entityDescriptor);
            return net.shibboleth.utilities.java.support.xml.SerializeSupport.prettyPrintXML(element);
        } catch (Exception e) {
            throw new IllegalStateException("Failed generating metadata", e);
        }
    }

    private org.opensaml.xmlsec.signature.KeyInfo buildKeyInfo(X509Certificate cert) {
        org.opensaml.xmlsec.signature.KeyInfo keyInfo =
                (org.opensaml.xmlsec.signature.KeyInfo) XMLObjectProviderRegistrySupport.getBuilderFactory()
                        .getBuilder(org.opensaml.xmlsec.signature.KeyInfo.DEFAULT_ELEMENT_NAME)
                        .buildObject(org.opensaml.xmlsec.signature.KeyInfo.DEFAULT_ELEMENT_NAME);
        org.opensaml.xmlsec.signature.X509Data x509Data =
                (org.opensaml.xmlsec.signature.X509Data) XMLObjectProviderRegistrySupport.getBuilderFactory()
                        .getBuilder(org.opensaml.xmlsec.signature.X509Data.DEFAULT_ELEMENT_NAME)
                        .buildObject(org.opensaml.xmlsec.signature.X509Data.DEFAULT_ELEMENT_NAME);
        org.opensaml.xmlsec.signature.X509Certificate x509Certificate =
                (org.opensaml.xmlsec.signature.X509Certificate) XMLObjectProviderRegistrySupport.getBuilderFactory()
                        .getBuilder(org.opensaml.xmlsec.signature.X509Certificate.DEFAULT_ELEMENT_NAME)
                        .buildObject(org.opensaml.xmlsec.signature.X509Certificate.DEFAULT_ELEMENT_NAME);
        x509Certificate.setValue(Base64.getEncoder().encodeToString(cert.getEncoded()));
        x509Data.getX509Certificates().add(x509Certificate);
        keyInfo.getX509Datas().add(x509Data);
        return keyInfo;
    }
}

@Service
class SamlResponseService {

    private final SamlProperties properties;
    private final SamlCredentialService credentialService;

    SamlResponseService(SamlProperties properties, SamlCredentialService credentialService) {
        this.properties = properties;
        this.credentialService = credentialService;
    }

    public SamlUser processResponse(String samlResponseEncoded) {
        try {
            byte[] decoded = Base64.getDecoder().decode(samlResponseEncoded);
            ByteArrayInputStream input = new ByteArrayInputStream(decoded);
            org.opensaml.core.xml.io.Unmarshaller unmarshaller = XMLObjectProviderRegistrySupport.getUnmarshallerFactory()
                    .getUnmarshaller(org.opensaml.core.xml.util.XMLObjectSupport.loadXML(input).getDocumentElement());
            Response response = (Response) unmarshaller.unmarshall(org.opensaml.core.xml.util.XMLObjectSupport.loadXML(new ByteArrayInputStream(decoded)).getDocumentElement());

            validateResponse(response);

            Assertion assertion = response.getAssertions().isEmpty() ? null : response.getAssertions().get(0);
            if (assertion == null) {
                throw new IllegalStateException("No assertion found");
            }

            validateAssertion(assertion);

            String nameId = assertion.getSubject() != null && assertion.getSubject().getNameID() != null
                    ? assertion.getSubject().getNameID().getValue() : null;

            Map<String, List<String>> attributes = new LinkedHashMap<>();
            for (AttributeStatement statement : assertion.getAttributeStatements()) {
                for (Attribute attribute : statement.getAttributes()) {
                    List<String> values = attribute.getAttributeValues().stream()
                            .map(v -> v.getDOM() != null ? v.getDOM().getTextContent() : v.getTextContent())
                            .collect(Collectors.toList());
                    attributes.put(attribute.getName(), values);
                }
            }

            return new SamlUser(nameId, attributes, response.getID(), assertion.getID());
        } catch (Exception e) {
            throw new IllegalStateException("Failed to process SAML response", e);
        }
    }

    private void validateResponse(Response response) throws SignatureException {
        if (response.getStatus() == null || response.getStatus().getStatusCode() == null ||
                !StatusCode.SUCCESS.equals(response.getStatus().getStatusCode().getValue())) {
            throw new IllegalStateException("SAML response status is not success");
        }
        if (response.getDestination() != null && !properties.getAcsUrl().equals(response.getDestination())) {
            throw new IllegalStateException("Invalid response destination");
        }
        if (response.getIssuer() != null && !properties.getIdpEntityId().equals(response.getIssuer().getValue())) {
            throw new IllegalStateException("Invalid issuer");
        }
        if (response.getIssueInstant() != null && response.getIssueInstant().isBefore(Instant.now().minusSeconds(300))) {
            throw new IllegalStateException("Response too old");
        }
        if (response.isSigned()) {
            validateSignature(response.getSignature());
        }
    }

    private void validateAssertion(Assertion assertion) throws SignatureException {
        if (properties.isWantAssertionsSigned()) {
            if (!assertion.isSigned()) {
                throw new IllegalStateException("Assertion must be signed");
            }
            validateSignature(assertion.getSignature());
        }
        if (assertion.getIssuer() != null && !properties.getIdpEntityId().equals(assertion.getIssuer().getValue())) {
            throw new IllegalStateException("Invalid assertion issuer");
        }
        Conditions conditions = assertion.getConditions();
        if (conditions != null) {
            Instant now = Instant.now();
            if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore().minusSeconds(60))) {
                throw new IllegalStateException("Assertion not yet valid");
            }
            if (conditions.getNotOnOrAfter() != null && !now.isBefore(conditions.getNotOnOrAfter())) {
                throw new IllegalStateException("Assertion expired");
            }
            if (!conditions.getAudienceRestrictions().isEmpty()) {
                boolean audienceOk = conditions.getAudienceRestrictions().stream()
                        .flatMap(ar -> ar.getAudiences().stream())
                        .anyMatch(a -> properties.getSpEntityId().equals(a.getURI()));
                if (!audienceOk) {
                    throw new IllegalStateException("Audience restriction failed");
                }
            }
        }
        Subject subject = assertion.getSubject();
        if (subject != null && subject.getSubjectConfirmations() != null) {
            boolean confirmationValid = false;
            for (SubjectConfirmation confirmation : subject.getSubjectConfirmations()) {
                SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
                if (SubjectConfirmation.METHOD_BEARER.equals(confirmation.getMethod()) && data != null) {
                    boolean recipientOk = data.getRecipient() == null || properties.getAcsUrl().equals(data.getRecipient());
                    boolean timeOk = data.getNotOnOrAfter() == null || Instant.now().isBefore(data.getNotOnOrAfter());
                    if (recipientOk && timeOk) {
                        confirmationValid = true;
                        break;
                    }
                }
            }
            if (!confirmationValid) {
                throw new IllegalStateException("No valid subject confirmation");
            }
        }
    }

    private void validateSignature(Signature signature) throws SignatureException {
        if (signature == null) {
            throw new IllegalStateException("Missing signature");
        }
        BasicX509Credential credential = credentialService.getIdpCredential();
        if (credential == null) {
            throw new IllegalStateException("IdP credential not configured");
        }
        SignatureValidator.validate(signature, credential);
    }
}

@RestController
class SamlController {

    private final SamlProperties properties;
    private final SamlRequestService requestService;
    private final SamlMetadataService metadataService;
    private final SamlResponseService responseService;

    SamlController(SamlProperties properties,
                   SamlRequestService requestService,
                   SamlMetadataService metadataService,
                   SamlResponseService responseService) {
        this.properties = properties;
        this.requestService = requestService;
        this.metadataService = metadataService;
        this.responseService = responseService;
    }

    @GetMapping("/saml/login")
    public void login(HttpServletResponse response) throws IOException {
        AuthnRequest authnRequest = requestService.buildAuthnRequest();
        String xml = serialize(authnRequest);
        String encoded = Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
        String html = "<html><body onload='document.forms[0].submit()'>" +
                "<form method='post' action='" + escape(properties.getIdpSsoUrl()) + "'>" +
                "<input type='hidden' name='SAMLRequest' value='" + escape(encoded) + "'/>" +
                "</form></body></html>";
        response.setContentType(MediaType.TEXT_HTML_VALUE);
        response.getWriter().write(html);
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public SamlUser acs(@RequestParam("SAMLResponse") String samlResponse) {
        return responseService.processResponse(samlResponse);
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata() {
        return metadataService.generateMetadata();
    }

    @GetMapping("/")
    public Map<String, String> home() {
        Map<String, String> map = new LinkedHashMap<>();
        map.put("login", "/saml/login");
        map.put("acs", "/saml/acs");
        map.put("metadata", "/saml/metadata");
        return map;
    }

    private String serialize(XMLObject object) {
        try {
            org.w3c.dom.Element element = org.opensaml.core.xml.util.XMLObjectSupport.marshall(object);
            return net.shibboleth.utilities.java.support.xml.SerializeSupport.nodeToString(element);
        } catch (Exception e) {
            throw new IllegalStateException("Unable to serialize SAML object", e);
        }
    }

    private String escape(String value) {
        return value == null ? "" : value.replace("&", "&amp;").replace("\"", "&quot;").replace("<", "&lt;").replace(">", "&gt;");
    }
}

class SamlUser {
    private final String nameId;
    private final Map<String, List<String>> attributes;
    private final String responseId;
    private final String assertionId;

    SamlUser(String nameId, Map<String, List<String>> attributes, String responseId, String assertionId) {
        this.nameId = nameId;
        this.attributes = attributes;
        this.responseId = responseId;
        this.assertionId = assertionId;
    }

    public String getNameId() {
        return nameId;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }

    public String getResponseId() {
        return responseId;
    }

    public String getAssertionId() {
        return assertionId;
    }
}